 1	import * as _ from "lodash-es";
 2	import * as React from "react";
 3	import * as classNames from "classnames";
 4	import { Alert, AlertGroup } from "@patternfly/react-core";
 5	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 6	import { LoadingInline } from "./utils/status-box";
 7	import { isObject } from "lodash-es";
 8	
 9	const injectDisabled = (children, disabled) => {
10	  return React.Children.map(children, (c) => {
11	    if (!isObject(c) || c.type !== "button") {
12	      return c;
13	    }
14	
15	    return React.cloneElement(c, { disabled: c.props.disabled || disabled });
16	  });
17	};
18	
19	const ErrorMessage = ({ message }) => {
20	  const { t } = useNodeHealthCheckTranslation();
21	  return (
22	    <Alert
23	      isInline
24	      className="co-alert co-alert--scrollable"
25	      variant="danger"
26	      title={t("An error occurred")}
27	    >
28	      <div className="co-pre-line">{message}</div>
29	    </Alert>
30	  );
31	};
32	const InfoMessage = ({ message }) => (
33	  <Alert isInline className="co-alert" variant="info" title={message} />
34	);
35	const SuccessMessage = ({ message }) => (
36	  <Alert isInline className="co-alert" variant="success" title={message} />
37	);
38	
39	// NOTE: DO NOT use <a> elements within a ButtonBar.
40	// They don't support the disabled attribute, and therefore
41	// can't be disabled during a pending promise/request.
42	/** @type {React.SFC<{children: any, className?: string, errorMessage?: React.ReactNode, infoMessage?: string, successMessage?: string, inProgress?: boolean}}>} */
43	export const ButtonBar = ({
44	  children,
45	  className,
46	  errorMessage,
47	  infoMessage,
48	  successMessage,
49	  inProgress,
50	}) => {
51	  return (
52	    <div className={classNames(className, "co-m-btn-bar")}>
53	      <AlertGroup
54	        isLiveRegion
55	        aria-live="polite"
56	        aria-atomic="false"
57	        aria-relevant="additions text"
58	      >
59	        {successMessage && <SuccessMessage message={successMessage} />}
60	        {errorMessage && <ErrorMessage message={errorMessage} />}
61	        {injectDisabled(children, inProgress)}
62	        {inProgress && <LoadingInline />}
63	        {infoMessage && <InfoMessage message={infoMessage} />}
64	      </AlertGroup>
65	    </div>
66	  );
67	};

